+    let terrain = [];
+    let bullets = [];
+    let enemies = [];
+    let enemyBullets = [];
+    let particles = [];
+    let powerups = [];
+    let shockwaves = [];
+    let boss = null;
+    let rafId = 0;
+    let audio = null;
+    let shake = 0;
+    let flash = 0;
+    let spawnTimer = 0;
+    let terrainTimer = 0;
+    let bossTimer = 0;
+    let lastTime = 0;
+    let state = 'menu';
+    let highScore = Number(localStorage.getItem('starwakeHighScore') || 0);
+
+    const keys = new Set();
+    const pointer = { active: false, x: 0, y: 0, fire: false };
+
+    const game = {
+      score: 0,
+      lives: 3,
+      shield: 100,
+      maxShield: 100,
+      weapon: 1,
+      weaponHeat: 0,
+      fireCooldown: 0,
