+
+    function makeMaterials() {
+      materials.player = new THREE.MeshStandardMaterial({ color: 0xdafcff, emissive: 0x1ccbc0, emissiveIntensity: 0.55, roughness: 0.28, metalness: 0.78 });
+      materials.playerDark = new THREE.MeshStandardMaterial({ color: 0x144a58, emissive: 0x071b22, roughness: 0.35, metalness: 0.72 });
+      materials.canopy = new THREE.MeshStandardMaterial({ color: 0x86efff, emissive: 0x2ccce8, emissiveIntensity: 0.8, roughness: 0.08, metalness: 0.15, transparent: true, opacity: 0.78 });
+      materials.thruster = new THREE.MeshBasicMaterial({ color: 0x3ff3df, transparent: true, opacity: 0.9 });
+      materials.bullet = new THREE.MeshBasicMaterial({ color: 0xefffff });
+      materials.enemy = new THREE.MeshStandardMaterial({ color: 0xff4f8f, emissive: 0x6d1134, emissiveIntensity: 0.75, roughness: 0.32, metalness: 0.55 });
+      materials.enemyAlt = new THREE.MeshStandardMaterial({ color: 0xffd166, emissive: 0x7d3f00, emissiveIntensity: 0.65, roughness: 0.42, metalness: 0.4 });
+      materials.enemyBullet = new THREE.MeshBasicMaterial({ color: 0xff6b4f });
+      materials.power = new THREE.MeshStandardMaterial({ color: 0x75ff88, emissive: 0x24c967, emissiveIntensity: 1.2, roughness: 0.18, metalness: 0.25 });
