+    }
+
+    function makeLights() {
+      scene.add(new THREE.AmbientLight(0x9edee7, 0.38));
+      const key = new THREE.DirectionalLight(0xffffff, 1.4);
+      key.position.set(-3, 5, 9);
+      scene.add(key);
+      const rim = new THREE.DirectionalLight(0xffd166, 0.75);
+      rim.position.set(7, -3, 5);
+      scene.add(rim);
+      playerLight = new THREE.PointLight(0x3ff3df, 1.1, 8);
+      scene.add(playerLight);
+    }
+
+    function makeBackground() {
+      for (let i = 0; i < 3; i += 1) {
+        const count = [520, 320, 180][i];
+        const positions = new Float32Array(count * 3);
+        const colors = new Float32Array(count * 3);
+        const palette = [new THREE.Color(0x9ffdf2), new THREE.Color(0xffd166), new THREE.Color(0x7db8ff), new THREE.Color(0xffffff)];
+        for (let j = 0; j < count; j += 1) {
+          positions[j * 3] = rand(WORLD.left - 4, WORLD.right + 26);
+          positions[j * 3 + 1] = rand(WORLD.bottom - 3, WORLD.top + 3);
+          positions[j * 3 + 2] = rand(-24 - i * 7, -12 - i * 3);
+          const c = palette[Math.floor(Math.random() * palette.length)];
+          colors[j * 3] = c.r;
+          colors[j * 3 + 1] = c.g;
+          colors[j * 3 + 2] = c.b;
+        }
+        const geo = new THREE.BufferGeometry();
+        geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
+        geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
+        const mat = new THREE.PointsMaterial({ size: [0.035, 0.06, 0.09][i], vertexColors: true, transparent: true, opacity: [0.52, 0.7, 0.95][i], depthWrite: false });
+        const points = new THREE.Points(geo, mat);
+        points.userData.speed = [1.1, 1.9, 3.2][i];
+        starLayers.push(points);
+        scene.add(points);
+      }
+
+      tunnel = new THREE.Group();
+      const ringGeo = new THREE.TorusGeometry(7.2, 0.018, 6, 96);
+      for (let i = 0; i < 24; i += 1) {
+        const mat = new THREE.MeshBasicMaterial({ color: i % 2 ? 0x193947 : 0x264e50, transparent: true, opacity: 0.2 });
+        const ring = new THREE.Mesh(ringGeo, mat);
+        ring.position.set(rand(WORLD.left, WORLD.right + 20), 0, -18 - i * 0.5);
+        ring.rotation.set(Math.PI / 2, 0, 0);
+        ring.scale.setScalar(rand(0.7, 1.25));
+        ring.userData.speed = rand(1.6, 2.7);
+        tunnel.add(ring);
+      }
+      scene.add(tunnel);
+    }
+
+    function makePlayer() {
+      player = new THREE.Group();
+      const body = new THREE.Mesh(new THREE.ConeGeometry(0.48, 1.65, 4), materials.player);
+      body.rotation.z = -Math.PI / 2;
+      body.scale.y = 1.15;
+      player.add(body);
+
+      const spine = new THREE.Mesh(new THREE.BoxGeometry(1.05, 0.2, 0.22), materials.playerDark);
+      spine.position.set(-0.08, 0, 0);
+      player.add(spine);
+
+      const wingGeo = new THREE.BoxGeometry(0.76, 0.12, 0.12);
+      const wingTop = new THREE.Mesh(wingGeo, materials.playerDark);
+      wingTop.position.set(-0.28, 0.47, 0);
+      wingTop.rotation.z = -0.48;
+      const wingBot = wingTop.clone();
+      wingBot.position.y = -0.47;
+      wingBot.rotation.z = 0.48;
+      player.add(wingTop, wingBot);
+
+      const canopy = new THREE.Mesh(new THREE.SphereGeometry(0.18, 18, 10), materials.canopy);
+      canopy.scale.set(1.25, 0.75, 0.64);
+      canopy.position.set(0.23, 0, 0.12);
+      player.add(canopy);
+
+      const flame = new THREE.Mesh(new THREE.ConeGeometry(0.24, 0.7, 18), materials.thruster);
+      flame.rotation.z = Math.PI / 2;
+      flame.position.x = -0.86;
+      flame.name = 'flame';
+      player.add(flame);
+
+      player.position.set(WORLD.left + 2.5, 0, 0);
+      player.userData.radius = 0.46;
+      scene.add(player);
+    }
+
+    function bindEvents() {
+      startBtn.addEventListener('click', startGame);
+      muteBtn.addEventListener('click', () => {
+        game.muted = !game.muted;
+        muteBtn.textContent = game.muted ? 'Sound Off' : 'Sound On';
+      });
+
+      window.addEventListener('resize', onResize);
+      window.addEventListener('keydown', (event) => {
+        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'Space'].includes(event.code)) event.preventDefault();
+        keys.add(event.code);
+        if (event.code === 'Enter' && state !== 'playing') startGame();
+        if (event.code === 'KeyP' && state === 'playing') togglePause();
+      });
+      window.addEventListener('keyup', (event) => keys.delete(event.code));
+
+      window.addEventListener('pointerdown', (event) => {
+        pointer.active = true;
+        pointer.fire = true;
+        updatePointer(event);
+        if (state !== 'playing') startGame();
+      });
+      window.addEventListener('pointermove', (event) => {
+        if (pointer.active) updatePointer(event);
+      });
+      window.addEventListener('pointerup', () => {
+        pointer.active = false;
+        pointer.fire = false;
+      });
+      window.addEventListener('pointercancel', () => {
+        pointer.active = false;
+        pointer.fire = false;
+      });
+      window.addEventListener('blur', () => {
+        keys.clear();
+        if (state === 'playing' && !game.paused) togglePause(true);
+      });
+    }
+
+    function onResize() {
+      renderer.setSize(window.innerWidth, window.innerHeight);
+      camera.aspect = window.innerWidth / window.innerHeight;
+      camera.updateProjectionMatrix();
+    }
+
+    function updatePointer(event) {
+      const nx = event.clientX / window.innerWidth;
+      const ny = event.clientY / window.innerHeight;
+      pointer.x = WORLD.left + nx * (WORLD.right - WORLD.left);
+      pointer.y = WORLD.top - ny * (WORLD.top - WORLD.bottom);
+    }
+
+    function startGame() {
+      if (state === 'playing') return;
+      ensureAudio();
+      resetGame();
+      state = 'playing';
+      menuEl.classList.add('hidden');
+      noticeEl.textContent = 'Collect green cores for shields and weapon upgrades. Survive until the sentinel arrives.';
+      clock.getDelta();
+      ping(220, 0.09, 'triangle', 0.04);
+    }
+
+    function resetGame() {
+      clearArray(bullets);
+      clearArray(enemies);
+      clearArray(enemyBullets);
+      clearArray(particles);
+      clearArray(powerups);
+      clearArray(shockwaves);
+      terrain.forEach((item) => scene.remove(item.mesh));
+      terrain = [];
+      if (boss) {
+        scene.remove(boss.mesh);
+        boss = null;
+      }
+      Object.assign(game, {
+        score: 0,
+        lives: 3,
+        shield: 100,
+        maxShield: 100,
+        weapon: 1,
+        weaponHeat: 0,
+        fireCooldown: 0,
+        invulnerable: 1.8,
+        time: 0,
+        rift: 1,
+        combo: 1,
+        comboTimer: 0,
+        paused: false,
+        bossDefeated: false
+      });
+      spawnTimer = 0.9;
+      terrainTimer = 0.4;
+      bossTimer = 70;
+      shake = 0;
+      flash = 0;
+      player.position.set(WORLD.left + 2.5, 0, 0);
+      player.visible = true;
+      updateHud();
+    }
+
+    function clearArray(items) {
+      for (const item of items) scene.remove(item.mesh);
+      items.length = 0;
+    }
+
+    function togglePause(force) {
+      game.paused = force === true ? true : !game.paused;
+      noticeEl.textContent = game.paused ? 'Paused. Press P to resume.' : 'Collect green cores for shields and weapon upgrades. Survive until the sentinel arrives.';
+    }
+
+    function animate(time) {
+      rafId = requestAnimationFrame(animate);
+      const rawDt = Math.min(0.033, (time - lastTime) / 1000 || clock.getDelta());
+      lastTime = time;
+      const dt = game.paused ? 0 : rawDt;
+
+      if (state === 'playing' && dt > 0) updateGame(dt);
+      updateBackground(rawDt);
+      render(rawDt);
+    }
+
+    function updateGame(dt) {
+      game.time += dt;
+      game.rift = 1 + Math.min(1.9, game.time / 72);
+      game.fireCooldown -= dt;
+      game.invulnerable = Math.max(0, game.invulnerable - dt);
+      game.comboTimer = Math.max(0, game.comboTimer - dt);
+      if (game.comboTimer === 0) game.combo = 1;
+      if (game.shield < game.maxShield) game.shield = Math.min(game.maxShield, game.shield + dt * 1.8);
+
+      updatePlayer(dt);
+      updateWeapons(dt);
+      spawnThings(dt);
+      updateBullets(dt);
+      updateEnemies(dt);
+      updateEnemyBullets(dt);
+      updatePowerups(dt);
+      updateTerrain(dt);
+      updateParticles(dt);
+      updateShockwaves(dt);
+      updateBoss(dt);
+      updateCollisions();
+      updateHud();
+    }
